(()=>{'use strict';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim();let overlay,body,selected=new Set();
function fmt(d){return d.toISOString().slice(0,10)}
function thai(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function daysBetween(a,b){const out=[],sa=new Date(a+'T00:00:00'),sb=new Date(b+'T00:00:00');if(isNaN(sa)||isNaN(sb))return out;for(let d=new Date(sa);d<=sb;d.setDate(d.getDate()+1))out.push(fmt(d));return out}
function cleanDates(a){return[...new Set((a||[]).map(T).filter(Boolean))].sort()}
function allDates(){const ds=cleanDates(window.DOIT_ALL_DATES||window.DOIT_AVAILABLE_DATES||[]);if(ds.length)return ds;const s=$('#startDate')?.value,e=$('#endDate')?.value;if(s&&e)return daysBetween(s,e);const today=fmt(new Date());return[s||e||today]}
function css(){if($('#dateCheckStyle'))return;const st=document.createElement('style');st.id='dateCheckStyle';st.textContent=`.datePickBtn{height:34px;border:1px solid #087b34;background:#f0fdf4;color:#087b34;border-radius:8px;padding:0 10px;font-weight:950;margin-left:8px}.dateOverlay{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:170;display:none;align-items:center!important;justify-content:center!important;padding:18px}.dateOverlay.on{display:flex}.dateSheet{width:min(92vw,720px);max-height:86vh;background:#fff;border-radius:18px;box-shadow:0 22px 80px #0006;display:flex;flex-direction:column;overflow:hidden}.dateHead{background:#087b34;color:#fff;padding:14px 16px;display:flex;justify-content:space-between;align-items:center;gap:8px;font-size:17px}.dateClose{height:34px;border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;font-weight:900;padding:0 12px}.dateBody{padding:12px;overflow:auto}.dateGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:9px}.dateItem{border:1px solid #d1d5db;background:#fff;border-radius:10px;padding:11px 9px;font-weight:950;text-align:left;display:flex;gap:9px;align-items:center;font-size:15px}.dateItem.on{border-color:#087b34;background:#ecfdf5;color:#065f27}.dateItem i{width:20px;height:20px;border:1px solid #9ca3af;border-radius:5px;display:inline-grid;place-items:center;font-style:normal;font-size:13px;flex:0 0 auto}.dateItem.on i{background:#087b34;color:#fff;border-color:#087b34}.dateFoot{padding:12px;border-top:1px solid #e5e7eb;display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px}.dateFoot button{height:46px;border-radius:10px;font-weight:950;font-size:15px}.dateClear{border:1px solid #d1d5db;background:#fff;color:#4b5563}.dateAll{border:1px solid #2563eb;background:#eff6ff;color:#1d4ed8}.dateOk{border:0;background:#087b34;color:#fff}.dateHint{font-size:13px;color:#4b5563;line-height:1.45;margin-bottom:10px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:9px}.dateCardFilters{margin-top:12px}.dateCardFilters.card{box-shadow:none;border-color:#bbf7d0;background:#f0fdf4}.dateCardFilters h3{display:none}.dateCardFilters .filterGrid{grid-template-columns:1fr!important;gap:8px}.dateCardFilters .searchLine{grid-template-columns:1fr!important;gap:8px;margin-top:8px}.dateCardFilters .mobileHint{font-size:11px}.dateCardFilters .field input,.dateCardFilters .field select{height:38px}.dateCardFilters .range{grid-template-columns:1fr 20px 1fr}.dateCardFilters .clear,.dateCardFilters .searchBtn{height:38px}@media(max-width:520px){.dateOverlay{padding:10px}.dateSheet{width:96vw;max-height:88vh}.dateGrid{grid-template-columns:repeat(2,1fr)}.dateItem{font-size:14px;padding:10px 8px}.dateHead{font-size:16px}}`;document.head.appendChild(st)}
function ensure(){css();if(!overlay){overlay=document.createElement('div');overlay.className='dateOverlay';overlay.innerHTML='<div class="dateSheet"><div class="dateHead"><b>เลือกวันที่แบบติ๊กมาร์ก</b><button class="dateClose">ปิด</button></div><div class="dateBody"></div><div class="dateFoot"><button class="dateClear">ล้าง</button><button class="dateAll">เลือกทั้งหมด</button><button class="dateOk">ตกลง</button></div></div>';document.body.appendChild(overlay);body=overlay.querySelector('.dateBody');overlay.querySelector('.dateClose').onclick=close;overlay.querySelector('.dateClear').onclick=()=>{selected.clear();render()};overlay.querySelector('.dateAll').onclick=()=>{selected=new Set(allDates());render()};overlay.querySelector('.dateOk').onclick=apply;overlay.onclick=e=>{if(e.target===overlay)close()}}}
function open(){ensure();const saved=cleanDates(window.DOIT_SELECTED_DATES||[]);selected.clear();saved.forEach(d=>selected.add(d));render();overlay.classList.add('on')}
function close(){overlay?.classList.remove('on')}
function render(){const all=allDates();const none=!selected.size;body.innerHTML='<div class="dateHint">ถ้าไม่ติ๊กวันใดเลย = ใช้ทุกวันในไฟล์<br>ถ้าติ๊กวันใด = ใช้เฉพาะวันที่ติ๊กจริง ไม่ดึงวันคั่นกลาง</div>'+ (none?'<div class="dateHint"><b>สถานะ: ทุกวัน</b></div>':'') + '<div class="dateGrid">'+all.map(d=>`<button class="dateItem ${selected.has(d)?'on':''}" data-d="${d}"><i>${selected.has(d)?'✓':''}</i><span>${thai(d)}</span></button>`).join('')+'</div>';body.querySelectorAll('.dateItem').forEach(b=>b.onclick=()=>{const d=b.dataset.d;if(selected.has(d))selected.delete(d);else selected.add(d);render()})}
function setVal(el,v){if(el)el.value=v}
function apply(){const arr=cleanDates([...selected]);window.DOIT_SELECTED_DATES=arr;window.DOIT_SELECTED_DATE_KEY=arr.join(',');if(arr.length){const first=arr[0],last=arr[arr.length-1];setVal($('#startDate'),first);setVal($('#endDate'),last);const p=$('#datePreview');if(p)p.textContent=arr.length===1?thai(first):`เลือก ${arr.length} วัน: ${thai(first)} - ${thai(last)}`}else{setVal($('#startDate'),'');setVal($('#endDate'),'');const p=$('#datePreview');if(p)p.textContent='ทุกวัน'}document.dispatchEvent(new CustomEvent('doit:selectedDatesChanged',{detail:{dates:arr,dateKey:window.DOIT_SELECTED_DATE_KEY,all:!arr.length}}));close()}
function moveFilters(){const filters=document.querySelector('section.filters'),dateCard=document.querySelector('#upload .topGrid .card:nth-child(2)');if(filters&&dateCard&&!filters.dataset.movedToDate){filters.dataset.movedToDate='1';filters.classList.add('dateCardFilters');dateCard.appendChild(filters)}}
function install(){ensure();moveFilters();const box=document.querySelector('.dateBox');if(box&&!$('#datePickBtn')){const b=document.createElement('button');b.id='datePickBtn';b.type='button';b.className='datePickBtn';b.textContent='✓ เลือกวัน';box.appendChild(b);b.onclick=e=>{e.stopPropagation();open()};box.onclick=open}document.querySelectorAll('.field label').forEach(l=>{if(l.textContent.includes('ช่วงวันที่'))l.textContent='วันที่ที่เลือก'});['startDate','endDate'].forEach(id=>{const el=$('#'+id);if(el&&!el.dataset.dateMark262){el.dataset.dateMark262='1';el.readOnly=true;el.addEventListener('click',e=>{e.preventDefault();open()})}})}
document.addEventListener('doit:dates',()=>{if(overlay?.classList.contains('on'))render()});document.addEventListener('DOMContentLoaded',()=>{install();setTimeout(install,600);setTimeout(install,1600)});if(document.readyState!=='loading')install();
})();